from collections import Counter

def is_balanced(s):
    # Count frequency of each character
    freq = Counter(s)

    # Check if all 26 letters appear
    if len(freq) != 26:
        return False

    # Check if all characters have the same frequency
    first_freq = next(iter(freq.values()))
    for count in freq.values():
        if count != first_freq:
            return False

    return True

T = int(input())
for _ in range(T):
    s = input().strip()
    if is_balanced(s):
        print("Yes")
    else:
        print("No")
