import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return

    n = int(data[0])
    U = int(data[1])
    E = list(map(int, data[2:2+n]))

    max_efficiency = -1.0

    # Try all possible i and find best k for each i
    for i in range(n - 2):
        # Find the maximum k such that E[k] - E[i] <= U
        # Since E is sorted, we can use binary search
        left, right = i + 2, n - 1
        best_k = i + 2  # At least j = i+1 exists

        while left <= right:
            mid = (left + right) // 2
            if E[mid] - E[i] <= U:
                best_k = mid
                left = mid + 1
            else:
                right = mid - 1

        # Now best_k is the maximum k for this i
        # Try all j from i+1 to best_k-1
        for j in range(i + 1, best_k):
            efficiency = (E[best_k] - E[j]) / (E[best_k] - E[i])
            if efficiency > max_efficiency:
                max_efficiency = efficiency

    if max_efficiency < 0:
        print(-1)
    else:
        print(f"{max_efficiency:.10f}")

if __name__ == "__main__":
    solve()
